// ============================================================
// NODE: Parse Meta Webhook Payload → Unified Message Object
// Supports: WhatsApp, Instagram DM, Facebook Messenger
// ============================================================

const body = $input.first().json.body;

let platform = 'unknown';
let sender_id = '';
let message_type = 'text';
let text = '';
let media_id = null;
let media_url = null;
let raw_entry = null;

try {
  // ── WhatsApp ──────────────────────────────────────────────
  if (body?.object === 'whatsapp_business_account') {
    platform = 'whatsapp';
    const entry = body.entry?.[0];
    const change = entry?.changes?.[0];
    const msg = change?.value?.messages?.[0];
    if (!msg) return []; // Delivery receipts, etc.

    sender_id = msg.from;
    raw_entry = msg;

    if (msg.type === 'text') {
      message_type = 'text';
      text = msg.text?.body || '';
    } else if (msg.type === 'audio' || msg.type === 'voice') {
      message_type = 'voice';
      media_id = msg.audio?.id || msg.voice?.id;
    } else if (msg.type === 'image') {
      message_type = 'image';
      media_id = msg.image?.id;
    } else if (msg.type === 'video') {
      message_type = 'video';
      media_id = msg.video?.id;
    } else if (msg.type === 'document') {
      message_type = 'document';
      media_id = msg.document?.id;
    }

  // ── Instagram DM ─────────────────────────────────────────
  } else if (body?.object === 'instagram') {
    platform = 'instagram';
    const messaging = body.entry?.[0]?.messaging?.[0];
    if (!messaging) return [];

    sender_id = messaging.sender?.id;
    raw_entry = messaging;

    if (messaging.message?.text) {
      message_type = 'text';
      text = messaging.message.text;
    } else if (messaging.message?.attachments) {
      const att = messaging.message.attachments[0];
      if (att.type === 'audio') { message_type = 'voice'; media_url = att.payload?.url; }
      else if (att.type === 'image') { message_type = 'image'; media_url = att.payload?.url; }
      else if (att.type === 'video') { message_type = 'video'; media_url = att.payload?.url; }
    }

  // ── Facebook Messenger ───────────────────────────────────
  } else if (body?.object === 'page') {
    platform = 'facebook';
    const messaging = body.entry?.[0]?.messaging?.[0];
    if (!messaging) return [];

    sender_id = messaging.sender?.id;
    raw_entry = messaging;

    if (messaging.message?.text) {
      message_type = 'text';
      text = messaging.message.text;
    } else if (messaging.message?.attachments) {
      const att = messaging.message.attachments[0];
      if (att.type === 'audio') { message_type = 'voice'; media_url = att.payload?.url; }
      else if (att.type === 'image') { message_type = 'image'; media_url = att.payload?.url; }
      else if (att.type === 'video') { message_type = 'video'; media_url = att.payload?.url; }
    }
  }
} catch(e) {
  console.error('Parse error:', e);
  return [];
}

if (!sender_id) return [];

return [{
  json: {
    platform,
    sender_id,
    message_type,
    text,
    media_id,
    media_url,
    timestamp: new Date().toISOString()
  }
}];

// ============================================================
// NODE: Download media from Meta CDN
// WhatsApp: First get media URL from Graph API using media_id
// Instagram/Facebook: URL is already in media_url
// ============================================================

const item = $input.first().json;
const META_TOKEN = process.env.META_ACCESS_TOKEN;
const PHONE_NUM_ID = process.env.META_PHONE_NUMBER_ID;

let downloadUrl = item.media_url;

// WhatsApp: resolve media_id → URL
if (item.platform === 'whatsapp' && item.media_id) {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://graph.facebook.com/v19.0/${item.media_id}`,
    headers: { 'Authorization': `Bearer ${META_TOKEN}` },
    json: true
  });
  downloadUrl = resp.url;
}

if (!downloadUrl) {
  return [{ json: { ...item, text: '[Media received but could not be downloaded]', processed_media: true } }];
}

// Download binary
const binaryResponse = await this.helpers.httpRequest({
  method: 'GET',
  url: downloadUrl,
  headers: { 'Authorization': `Bearer ${META_TOKEN}` },
  encoding: 'arraybuffer',
  returnFullResponse: true
});

const contentType = binaryResponse.headers['content-type'] || 'application/octet-stream';
const buffer = Buffer.from(binaryResponse.body);
const base64 = buffer.toString('base64');

return [{ json: { ...item, media_base64: base64, media_content_type: contentType, media_download_url: downloadUrl } }];

// ============================================================
// NODE: Process media based on type
// Voice → OpenAI Whisper transcription (supports Arabic/Darja/French)
// Image → GPT-4o Vision description
// Video/Doc → Acknowledgment text
// ============================================================

const item = $input.first().json;
const OPENAI_KEY = process.env.OPENAI_API_KEY;

if (!item.media_base64) {
  return [{ json: { ...item, text: item.text || '[Media received]' } }];
}

const buffer = Buffer.from(item.media_base64, 'base64');

if (item.message_type === 'voice' || item.message_type === 'audio') {
  // ── Whisper Transcription ──────────────────────────────
  const FormData = require('form-data');
  const form = new FormData();

  const filename = item.media_content_type?.includes('ogg') ? 'audio.ogg' :
                   item.media_content_type?.includes('mpeg') ? 'audio.mp3' : 'audio.ogg';

  form.append('file', buffer, { filename, contentType: item.media_content_type || 'audio/ogg' });
  form.append('model', 'whisper-1');
  form.append('language', 'ar'); // Arabic covers Darja best
  form.append('prompt', 'This may be Algerian Darja dialect, French, or Arabic. Transcribe as accurately as possible.');

  const whisperResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/audio/transcriptions',
    headers: {
      'Authorization': `Bearer ${OPENAI_KEY}`,
      ...form.getHeaders()
    },
    body: form,
    json: true
  });

  const transcribedText = whisperResp.text || '[Voice message could not be transcribed]';
  return [{ json: { ...item, text: transcribedText, original_type: 'voice', transcribed: true } }];

} else if (item.message_type === 'image') {
  // ── GPT-4o Vision ─────────────────────────────────────
  const visionResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: {
      'Authorization': `Bearer ${OPENAI_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: 'gpt-4o',
      messages: [{
        role: 'user',
        content: [
          {
            type: 'text',
            text: 'Describe this image in detail. If it shows a car, mention make, model, color, condition, and any visible details. If it is a document, describe its content. Be concise (max 3 sentences). Respond in French.'
          },
          {
            type: 'image_url',
            image_url: {
              url: `data:${item.media_content_type || 'image/jpeg'};base64,${item.media_base64}`,
              detail: 'high'
            }
          }
        ]
      }],
      max_tokens: 300
    },
    json: true
  });

  const imageDescription = visionResp.choices?.[0]?.message?.content || '[Image received but could not be analyzed]';
  return [{ json: { ...item, text: `[Photo reçue] ${imageDescription}`, original_type: 'image', vision_analyzed: true } }];

} else {
  // Video / Document → simple acknowledgment
  const typeLabels = { video: 'Vidéo', document: 'Document' };
  return [{ json: { ...item, text: `[${typeLabels[item.message_type] || 'Fichier'} reçu]`, original_type: item.message_type } }];
}

// ============================================================
// NODE: Fetch Car Inventory (Sales + Rental) from Supabase
// Only runs if business_type_slug === 'car_showroom'
// ============================================================

const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_KEY;
const AGENCY_ID = process.env.AGENCY_ID;

const headers = {
  'apikey': SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json'
};

let sales = [];
let rental = [];

try {
  // Fetch sales inventory
  const salesResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/car_sales_inventory?select=id,make,model,year,price,mileage,fuel_type,transmission,color,condition,description&agency_id=eq.${AGENCY_ID}&status=eq.available&limit=50`,
    headers,
    json: true
  });
  sales = Array.isArray(salesResp) ? salesResp : [];
} catch(e) { console.warn('Sales fetch error:', e.message); }

try {
  // Fetch rental fleet
  const rentalResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/car_rental_fleet?select=id,make,model,year,daily_rate,fuel_type,transmission,color,seats&agency_id=eq.${AGENCY_ID}&status=eq.available&limit=30`,
    headers,
    json: true
  });
  rental = Array.isArray(rentalResp) ? rentalResp : [];
} catch(e) { console.warn('Rental fetch error:', e.message); }

return [{ json: { sales_cars: sales, rental_cars: rental } }];

// ============================================================
// NODE: Build Dynamic System Prompt from chatbot_config
// All text is driven by the dashboard settings — no hardcoding
// ============================================================

const msgData = $('Merge Text + Media').item.json;
const agencyData = $('Fetch Agency Config from Supabase').item.json;
const historyItems = $('Fetch Conversation History').all();
const carsData = $('Fetch Car Inventory').item.json;

const agency = Array.isArray(agencyData) ? agencyData[0] : agencyData;
const config = agency?.chatbot_config || {};
const businessType = agency?.business_type_slug || 'car_showroom';
const companyName = agency?.company_name || 'Notre Showroom';

// Pull settings with safe defaults
const botName = config.personality?.bot_name || 'Assistant';
const greeting = config.personality?.bot_greeting || `Salam ! Bienvenue chez ${companyName}. Comment puis-je vous aider ?`;
const tone = config.personality?.response_tone || 'Friendly & Casual';
const langStyle = config.personality?.language_style || 'Algerian Darja';
const useEmojis = config.personality?.use_emojis !== false;
const formalityLevel = config.personality?.formality_level || 5;
const maxLength = config.behavior?.max_message_length || 600;
const autoQualify = config.behavior?.auto_qualify_leads !== false;
const handoffMsg = config.behavior?.handoff_message || 'Un conseiller va prendre le relais.';
const pricingRules = config.knowledge?.pricing_rules || '';
const allowedCars = config.knowledge?.allowed_trips || []; // reuses allowed_trips field for car IDs

// Build language instruction
const langInstructions = {
  'Algerian Darja': 'You MUST respond primarily in Algerian Darja (دارجة جزائرية — the everyday spoken Arabic of Algeria). Naturally mix in French words as Algerians do in real conversation (Arabizi / code-switching). Examples: "wach" (هل), "brabi" (please), "barka" (enough), "kima" (like), "chkoun" (who), "wayn" (where), "fin" (where). If the customer writes in French only, reply in French. If they write in Arabic (MSA), reply in Arabic. Mirror the customer language naturally.',
  'French': 'Respond in French. Use formal "vous" unless the customer uses "tu" first.',
  'Modern Standard Arabic': 'Respond in Modern Standard Arabic (الفصحى). Be respectful and formal.'
};
const langInstruction = langInstructions[langStyle] || langInstructions['Algerian Darja'];

// Build car catalog section
let catalogSection = '';
if (businessType === 'car_showroom') {
  const sales = carsData?.sales_cars || [];
  const rental = carsData?.rental_cars || [];

  // Filter to allowed cars if list is set, else show all
  const filteredSales = allowedCars.length > 0 ? sales.filter(c => allowedCars.includes(c.id)) : sales;
  const filteredRental = allowedCars.length > 0 ? rental.filter(c => allowedCars.includes(c.id)) : rental;

  if (filteredSales.length > 0) {
    catalogSection += `\n## 🚗 Voitures Disponibles à la Vente:\n`;
    filteredSales.forEach(c => {
      catalogSection += `- ${c.year} ${c.make} ${c.model}${c.color ? ` (${c.color})` : ''}: **${Number(c.price).toLocaleString('fr-DZ')} DZD**`;
      if (c.mileage) catalogSection += ` | ${Number(c.mileage).toLocaleString()} km`;
      if (c.fuel_type) catalogSection += ` | ${c.fuel_type}`;
      if (c.transmission) catalogSection += ` | ${c.transmission}`;
      catalogSection += `\n`;
    });
  }

  if (filteredRental.length > 0) {
    catalogSection += `\n## 🔑 Véhicules Disponibles à la Location:\n`;
    filteredRental.forEach(c => {
      catalogSection += `- ${c.year} ${c.make} ${c.model}${c.color ? ` (${c.color})` : ''}: **${Number(c.daily_rate).toLocaleString('fr-DZ')} DZD/jour**`;
      if (c.seats) catalogSection += ` | ${c.seats} places`;
      if (c.fuel_type) catalogSection += ` | ${c.fuel_type}`;
      catalogSection += `\n`;
    });
  }

  if (!filteredSales.length && !filteredRental.length) {
    catalogSection = `\n## Catalogue:\nLe catalogue est en cours de mise à jour. Invitez le client à laisser ses coordonnées.\n`;
  }
}

// Build FAQ section
const faqItems = config.faq || [];
let faqSection = '';
if (faqItems.length > 0) {
  faqSection = `\n## ❓ FAQ Connue (répondez à ces questions avec ces réponses exactes):\n`;
  faqItems.forEach(f => {
    faqSection += `Q: ${f.question}\nR: ${f.answer}\n\n`;
  });
}

// Build pricing rules section
let pricingSection = pricingRules ? `\n## 💰 Règles de Tarification:\n${pricingRules}\n` : '';

// Build business type specific persona
const businessPersona = businessType === 'car_showroom'
  ? `Tu es un expert en vente et location de véhicules neufs et d'occasion. Tu connais tous les modèles du catalogue. Tu peux aider pour : achats, locations, financement, essais routiers, reprise d'anciens véhicules, suivi de commandes importées, et dédouanement.`
  : businessType === 'travel_agency'
    ? `Tu es un expert en voyages et circuits touristiques. Tu connais toutes les destinations, les prix, les formalités de visa, et les offres spéciales.`
    : `Tu es un assistant virtuel professionnel.`;

// Build lead qualification instruction
const qualifyInstruction = autoQualify
  ? `\n## 🎯 Qualification Lead:\nDans ta conversation, essaie naturellement de collecter : le prénom du client, son numéro de téléphone, et ce qu'il recherche exactement. Ne demande pas tout d'un coup — intègre ces questions naturellement dans la conversation.`
  : '';

// Build tone instruction
const toneMap = {
  'Friendly & Casual': 'Sois amical, chaleureux, et décontracté.',
  'Professional & Formal': 'Sois professionnel, courtois, et formel.',
  'Enthusiastic & Salesy': 'Sois enthousiaste, persuasif, et orienté vente. Mets en avant les offres.'
};
const toneInstruction = toneMap[tone] || toneMap['Friendly & Casual'];

// Build emoji instruction
const emojiInstruction = useEmojis
  ? 'Utilise des emojis avec modération pour rendre la conversation plus vivante.'
  : "N'utilise pas d'emojis.";

// Compile the full system prompt
const systemPrompt = `Tu es ${botName}, l'assistant IA de **${companyName}**.
${businessPersona}

## 🗣️ Langue et Style:
${langInstruction}
${toneInstruction}
${emojiInstruction}
Longueur max des réponses: ${maxLength} caractères. Sois concis et direct.
${catalogSection}
${faqSection}
${pricingSection}
${qualifyInstruction}

## ⚠️ Règles Absolues:
1. Ne jamais inventer de prix ou de modèles de voitures. Utilise UNIQUEMENT les informations du catalogue fourni ci-dessus.
2. Si tu ne connais pas la réponse, dis-le honnêtement et propose de transférer à un humain.
3. Si on te demande quelque chose hors du contexte du showroom, redirige poliment.
4. Si c'est en dehors des heures d'ouverture, informe le client et dis-lui qu'on le recontactera.
5. Message de transfert humain à utiliser si nécessaire: "${handoffMsg}"
`;

// Build conversation history messages array (reversed to be chronological)
const history = historyItems
  .map(item => item.json)
  .filter(h => h.role && h.content)
  .reverse()
  .slice(-10)
  .map(h => ({ role: h.role, content: h.content }));

return [{
  json: {
    system_prompt: systemPrompt,
    history_messages: history,
    user_message: msgData.text,
    sender_id: msgData.sender_id,
    platform: msgData.platform,
    message_type: msgData.message_type,
    agency_id: process.env.AGENCY_ID,
    config_creativity: config.advanced?.creativity_level ?? 50,
    config_max_tokens: config.advanced?.max_response_tokens ?? 600,
    config_model: config.advanced?.ai_model || 'gpt-4o'
  }
}];

// ============================================================
// NODE: Extract AI reply text from OpenAI response
// ============================================================

const openaiResp = $input.first().json;
const promptData = $('Build Dynamic System Prompt').item.json;

const aiReply = openaiResp.choices?.[0]?.message?.content || 'Désolé, je ne peux pas répondre pour le moment. Veuillez réessayer.';

return [{
  json: {
    ai_reply: aiReply,
    sender_id: promptData.sender_id,
    platform: promptData.platform,
    message_type: promptData.message_type,
    user_message: promptData.user_message,
    agency_id: promptData.agency_id
  }
}];

// ============================================================
// NODE: Send Reply via Meta API
// Routes based on platform: WhatsApp / Instagram / Facebook
// ============================================================

const item = $('Extract AI Reply').item.json;
const META_TOKEN = process.env.META_ACCESS_TOKEN;
const PHONE_NUM_ID = process.env.META_PHONE_NUMBER_ID;

const aiReply = item.ai_reply;
const senderId = item.sender_id;
const platform = item.platform;

// Clean reply: WhatsApp doesn't support markdown bold (**text**)
// Convert **bold** → plain for WhatsApp, keep for Instagram/Facebook
const cleanForWhatsApp = (text) => text.replace(/\*\*(.*?)\*\*/g, '*$1*'); // WhatsApp uses single *
const cleanForMeta = (text) => text.replace(/\*\*(.*?)\*\*/g, '$1'); // Facebook/Instagram: strip

let response;

try {
  if (platform === 'whatsapp') {
    response = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/v19.0/${PHONE_NUM_ID}/messages`,
      headers: {
        'Authorization': `Bearer ${META_TOKEN}`,
        'Content-Type': 'application/json'
      },
      body: {
        messaging_product: 'whatsapp',
        recipient_type: 'individual',
        to: senderId,
        type: 'text',
        text: { body: cleanForWhatsApp(aiReply) }
      },
      json: true
    });
  } else if (platform === 'instagram') {
    response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://graph.facebook.com/v19.0/me/messages',
      headers: {
        'Authorization': `Bearer ${META_TOKEN}`,
        'Content-Type': 'application/json'
      },
      body: {
        recipient: { id: senderId },
        message: { text: cleanForMeta(aiReply) }
      },
      json: true
    });
  } else if (platform === 'facebook') {
    response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://graph.facebook.com/v19.0/me/messages',
      headers: {
        'Authorization': `Bearer ${META_TOKEN}`,
        'Content-Type': 'application/json'
      },
      body: {
        recipient: { id: senderId },
        message: { text: cleanForMeta(aiReply) }
      },
      json: true
    });
  }
} catch(err) {
  console.error('Meta send error:', err.message);
  return [{ json: { success: false, error: err.message } }];
}

return [{ json: { success: true, platform, sender_id: senderId, response } }];

// Merge: either the text-only path or the media-processed path
const items = $input.all();
const item = items[0]?.json || {};
return [{ json: item }];
